import React, { Component } from 'react';
import Papa from 'papaparse';
import logo from './logo.svg';
import {
  InputGroup, Input, Label, FormGroup,
  Button, Modal, ModalHeader, ModalBody, ModalFooter,
  ListGroup, ListGroupItem
} from 'reactstrap';
import ReactTable from "react-table";
import Spinner from 'react-spinkit';

import './App.css';
import "react-table/react-table.css";


class App extends Component {
  constructor() {
    super();
    this.state = {
      data: [],
      subdata: [],
      fields: [],
      searchText: '',
      selectedField: 'Title',
      dropdownOpen: false,
      loading: false,
      showModal: false,
      modalInfo: {}
    };
  }

  handleSearchTextChange = (event) => {
    this.setState({ searchText: event.target.value, loading: true });
    if (!event.target.value.length) {
      this.setState({ subdata: this.state.data, loading: false });
    }
    else {
      this.setState({
        subdata: this.state.data.filter(item => {
          const re = new RegExp(event.target.value, 'gi');
          if (re.test(item[this.state.selectedField])) {
            return true;
          }
          else {
            return false;
          }
        }),
        loading: false
      });
    }

  }

  handleFieldSelectorChange = (event) => {
    this.setState({ subdata: this.state.data, selectedField: event.target.value });
  }

  rowClicked = (rowInfo) => {
    this.setState({ showModal: true, modalInfo: rowInfo });
  }

  toggleModal = () => {
    this.setState({ showModal: !this.state.showModal });
  }

  componentWillMount() {
    this.setState({ loading: true });
    Papa.parse('./Catalogue.csv', {
      download: true,
      header: true,
      complete: (results) => {
        this.setState({
          data: results.data.map(item => {
            delete item[""];
            return item;
          }),
          subdata: results.data.map(item => {
            delete item[""];
            return item;
          }),
          fields: Object.keys(results.data[0]).filter(item => item !== ""),
          loading: false
        });
      }
    });
  }

  render() {
    const columns = this.state.fields.map(field => {
      return {
        Header: field,
        accessor: field
      };
    });

    const Tabb = () => (
      <ReactTable
        data={this.state.subdata}
        columns={columns}
        defaultPageSize={10}
        className="-striped -highlight"
        getTdProps={(state, rowInfo, column, instance) => {
          return {
            onClick: (e, handleOriginal) => {
              this.rowClicked(rowInfo);
            }
          }
        }}
      />
    );

    const Modd = () => (
      <Modal isOpen={this.state.showModal} toggle={this.toggleModal} className={this.props.className}>
        <ModalHeader toggle={this.toggleModal}></ModalHeader>
        <ModalBody>
          <ListGroup>
            {this.state.modalInfo.row ?
              this.state.fields.map((item, i) => {
                return <ListGroupItem key={i}>{`${item}: ${this.state.modalInfo.row[item]}`}</ListGroupItem>
              })
              : null
            }
          </ListGroup>
        </ModalBody>
        <ModalFooter>
          <Button color="primary" onClick={this.toggleModal}>Close</Button>{' '}
        </ModalFooter>
      </Modal>
    );

    return (
      <div className="container">
        <Modd />
        <header className="App-header">
          {/* <img src={logo} className="App-logo" alt="logo" /> */}
          <h1 className="App-title">Catalogue Search</h1>
        </header>
        <FormGroup className="docs-example">
          <Label for="searchText">Enter Search Text</Label>
          <Input
            id="searchText"
            value={this.state.searchText}
            onChange={this.handleSearchTextChange}
            className="searchBox"
          />
          <Label for="fieldSelector">Search By</Label>
          <Input
            type="select"
            name="select"
            id="fieldSelector"
            onChange={this.handleFieldSelectorChange}
            value={this.state.selectedField}
            className="fieldSelector"
          >
            {this.state.fields.map((item, i) => {
              return <option key={i}>{item}</option>
            })}
          </Input>
        </FormGroup>
        {
          this.state.searchText.length > 0
            ? this.state.loading ?
              <Spinner name='double-bounce' />
              : <Tabb />
            : null
        }
      </div>
    );
  }
}

export default App;



